  8→namespace TmRobotEx.Bridge;
  9→
 10→/// <summary>
 11→/// TCP 5001 브릿지 서버.
 12→/// sd_bridge.py의 C# 포팅.
 13→/// TMscript(TCP) → 이 서버 → Compute Box(XML-RPC)
 14→/// </summary>
 15→public class BridgeServer
 16→{
 17→    private TcpListener? _listener;
 18→    private CancellationTokenSource? _cts;
 19→    private readonly int _port;
 20→    private readonly SemaphoreSlim _cmdLock = new(1, 1);
 21→
 22→    private const double BUSY_POLL_SEC = 0.1;
 23→    private const double BUSY_TIMEOUT_SEC = 30;
 24→
 25→    public ComputeBoxClient CbClient { get; }
 26→    public WorkPlateData? PlateData { get; set; }
 27→
 28→    // 시나리오 연동
 29→    private ScrewScenario? _scenario;
 30→    private int _currentStepIndex;
 31→    private bool _scenarioRunning;
 32→
 33→    // 마지막 체결 결과 (tqDecision 용)
 34→    private bool _lastTightenOk;
 35→
 36→    // next_step 블로킹 대기용
 37→    private TaskCompletionSource<bool>? _scenarioReadyTcs;
 38→    private readonly object _tcsLock = new();
 39→
 40→    public event Action<string>? LogMessage;
 41→
 42→    /// <summary>
 43→    /// 스텝 시작 (stepIndex, operation) — TMflow가 next_step 요청 시
 44→    /// </summary>
 45→    public event Action<int, ScrewOperation>? StepStarted;
 46→
 47→    /// <summary>
 48→    /// 스텝 완료 (stepIndex, operation, success, achievedTorque) — TMflow가 step_result 보고 시
 49→    /// </summary>
 50→    public event Action<int, ScrewOperation, bool, double>? StepCompleted;
 51→
 52→    /// <summary>
 53→    /// 시나리오 전체 완료
 54→    /// </summary>
 55→    public event Action? ScenarioCompleted;
 56→
 57→    public BridgeServer(int port, string cbUrl, int cbTimeout)
 58→    {
 59→        _port = port;
 60→        CbClient = new ComputeBoxClient(cbUrl, cbTimeout);
 61→        // CB 로그를 브릿지 로그로 전달
 62→        CbClient.LogMessage += msg => LogMessage?.Invoke(msg);
 63→    }
 64→
 65→    private void Log(string tag, string msg) => LogMessage?.Invoke($"[{tag}] {msg}");
 66→
 67→    /// <summary>
 68→    /// 시나리오 실행 모드 시작 (TMflow 대기)
 69→    /// </summary>
 70→    public void StartScenario(ScrewScenario scenario)
 71→    {
 72→        _scenario = scenario;
 73→        _currentStepIndex = 0;
 74→        _scenarioRunning = true;
 75→        Log("시나리오", $"시작: {scenario.Name} ({scenario.Operations.Count}개 스텝)");
 76→
 77→        // 블로킹 대기 중인 next_step 요청 깨우기
 78→        lock (_tcsLock)
 79→        {
 80→            _scenarioReadyTcs?.TrySetResult(true);
 81→            _scenarioReadyTcs = null;
 82→        }
 83→    }
 84→
 85→    /// <summary>
 86→    /// 시나리오 실행 모드 정지
 87→    /// </summary>
 88→    public void StopScenario()
 89→    {
 90→        _scenarioRunning = false;
 91→        _scenario = null;
 92→        Log("시나리오", "중지");
 93→
 94→        // 블로킹 대기 중인 next_step 요청 취소
 95→        lock (_tcsLock)
 96→        {
 97→            _scenarioReadyTcs?.TrySetResult(false);
 98→            _scenarioReadyTcs = null;
 99→        }
100→    }
101→
102→    public bool IsScenarioRunning => _scenarioRunning;
103→
104→    /// <summary>
105→    /// UI에서 직접 명령 실행 (브릿지 디스패처 경유)
106→    /// </summary>
107→    public Task<string> ExecuteAsync(string cmdLine) => DispatchAsync(cmdLine);
108→
109→    public Task StartAsync()
110→    {
111→        _cts = new CancellationTokenSource();
112→        _listener = new TcpListener(IPAddress.Any, _port);
113→        _listener.Server.SetSocketOption(
114→            System.Net.Sockets.SocketOptionLevel.Socket,
115→            System.Net.Sockets.SocketOptionName.ReuseAddress, true);
116→        _listener.Start();
117→        Log("서버", $"대기 중 — 0.0.0.0:{_port}");
118→
119→        // 수신 루프 (백그라운드)
120→        _ = Task.Run(() => AcceptLoop(_cts.Token));
121→
122→        // Compute Box 연결 확인 (백그라운드, 서버 시작 후)
123→        _ = Task.Run(CheckComputeBoxAsync);
124→
125→        return Task.CompletedTask;
126→    }
127→
128→    private async Task CheckComputeBoxAsync()
129→    {
130→        Log("초기화", $"Compute Box ({CbClient.Url}) 연결 중...");
131→        try
132→        {
133→            var busy = await CbClient.GetBusyAsync();
134→            var torque = await CbClient.GetTorqueAsync();
135→            var error = await CbClient.GetErrorCodeAsync();
136→            Log("초기화", "Compute Box 연결 OK");
137→            Log("초기화", $"  busy={Convert.ToInt32(busy)}  torque={torque:F2}  error={error}");
138→        }
139→        catch (Exception ex)
140→        {
141→            Log("오류", $"Compute Box 연결 실패: {ex.Message}");
142→            Log("오류", "Compute Box 전원/네트워크 확인 후 재시도");
143→        }
144→    }
145→
146→    public void Stop()
147→    {
148→        Log("서버", "종료 중...");
149→        _cts?.Cancel();
150→        try { _listener?.Stop(); } catch { }
151→        _listener = null;
152→        CbClient.Dispose();
153→
154→        lock (_tcsLock)
155→        {
156→            _scenarioReadyTcs?.TrySetResult(false);
157→            _scenarioReadyTcs = null;
158→        }
159→        Log("서버", "종료 완료");
160→    }
161→
162→    private async Task AcceptLoop(CancellationToken token)
163→    {
164→        while (!token.IsCancellationRequested)
165→        {
166→            try
167→            {
168→                var client = await _listener!.AcceptTcpClientAsync(token);
169→                var addr = ((IPEndPoint)client.Client.RemoteEndPoint!).Address;
170→                Log("연결", $"{addr} 접속");
171→                _ = Task.Run(() => HandleClient(client, addr.ToString(), token));
172→            }
173→            catch (OperationCanceledException) { break; }
174→            catch (Exception ex)
175→            {
176→                if (!token.IsCancellationRequested)
177→                    Log("오류", $"Accept 오류: {ex.Message}");
178→            }
179→        }
180→    }
181→
182→    private async Task HandleClient(TcpClient client, string addr, CancellationToken token)
183→    {
184→        try
185→        {
186→            client.ReceiveTimeout = 60000;
187→            using var stream = client.GetStream();
188→            // BOM 없는 UTF-8 (파이썬 브릿지와 동일)
189→            var utf8 = new UTF8Encoding(false);
190→            using var reader = new StreamReader(stream, utf8, detectEncodingFromByteOrderMarks: false);
191→            var buf = new byte[4096];
192→
193→            while (!token.IsCancellationRequested)
194→            {
195→                string? line;
196→                try
197→                {
198→                    line = await reader.ReadLineAsync(token);
199→                }
200→                catch { break; }
201→
202→                if (line == null) break;
203→
204→                line = line.Trim();
205→                if (string.IsNullOrEmpty(line)) continue;
206→
207→                Log("수신", $"{addr} > {line}");
208→                var t0 = DateTime.Now;
209→
210→                string result;
211→                try
212→                {
213→                    result = await DispatchAsync(line);
214→                }
215→                catch (Exception ex)
216→                {
217→                    result = $"ERR:{ex.Message}";
218→                    Log("오류", $"처리 중 예외: {ex.Message}");
219→                }
220→
221→                var ms = (DateTime.Now - t0).TotalMilliseconds;
222→                Log("응답", $"{addr} < {result}  ({ms:F0}ms)");
223→
224→                // 파이썬과 동일: result + \r\n, 바이트로 직접 전송
225→                try
226→                {
227→                    var responseBytes = utf8.GetBytes(result + "\r\n");
228→                    await stream.WriteAsync(responseBytes, token);
229→                    await stream.FlushAsync(token);
230→                }
231→                catch { break; }
232→            }
233→        }
234→        catch (OperationCanceledException) { }
235→        catch (Exception ex)
236→        {
237→            if (!token.IsCancellationRequested)
238→                Log("오류", $"{addr} 핸들러 예외: {ex.Message}");
239→        }
240→        finally
241→        {
242→            try { client.Close(); } catch { }
243→            Log("종료", $"{addr} 연결 끊김");
244→        }
245→    }
246→
247→    /// <summary>
248→    /// 명령 디스패처 (SemaphoreSlim으로 직렬화)
249→    /// </summary>
250→    private async Task<string> DispatchAsync(string cmdLine)
251→    {
252→        var parts = cmdLine.Split(' ', StringSplitOptions.RemoveEmptyEntries);
253→        if (parts.Length == 0) return "ERR:빈 명령";
254→
255→        var cmd = parts[0].ToLower();
256→        var args = parts[1..];
257→
258→        // next_step은 블로킹 대기하므로 cmdLock 밖에서 처리
259→        if (cmd == "next_step")
260→        {
261→            try { return await CmdNextStepAsync(); }
262→            catch (Exception ex)
263→            {
264→                Log("오류", $"dispatch 예외: {ex.Message}");
265→                return $"ERR:{ex.Message}";
266→            }
267→        }
268→
269→        await _cmdLock.WaitAsync();
270→        try
271→        {
272→            return cmd switch
273→            {
274→                "config" => await CmdConfig(args),
275→                "pickup" => await CmdPickup(args),
276→                "tighten" => await CmdTighten(args),
277→                "loosen" => await CmdLoosen(args),
278→                "shank" => await CmdShank(args),
279→                "stop" => await CmdStop(),
280→                "status" => await CmdStatus(),
281→                "recover" => await CmdRecover(),
282→                "raw" => await CmdRaw(args),
283→                "next_hole" => CmdNextHole(),
284→                "hole_result" => CmdHoleResult(args),
285→                "get_coord" => CmdGetCoord(args),
286→                "tqdecision" => CmdTqDecision(),
287→                _ => $"ERR:unknown '{cmd}'"
288→            };
289→        }
290→        catch (Exception ex)
291→        {
292→            Log("오류", $"dispatch 예외: {ex.Message}");
293→            return $"ERR:{ex.Message}";
294→        }
295→        finally
296→        {
297→            _cmdLock.Release();
298→        }
299→    }
300→
301→    #region 기본 명령 (sd_bridge.py 동일)
302→
303→    private async Task<string> CmdConfig(string[] args)
304→    {
305→        double extender = args.Length > 0 && double.TryParse(args[0], out var e) ? e : 0;
306→        await CbClient.ConfigAsync(extender);
307→        return $"OK:config extender={extender}";
308→    }
309→
310→    private async Task<string> CmdPickup(string[] args)
311→    {
312→        if (args.Length < 2) return "ERR:pickup <force_N> <len_mm>";
313→        int force = int.Parse(args[0]);
314→        double length = double.Parse(args[1]);
315→
316→        await CbClient.PickupScrewAsync(force, length);
317→        var done = await WaitUntilDone(waitStart: true);
318→        var error = await CbClient.GetErrorCodeAsync();
319→        if (!done) return $"ERR:pickup timeout,error={error}";
320→        if (error != 0) return $"ERR:pickup error={error}";
321→        return "OK:pickup";
322→    }
323→
324→    private async Task<string> CmdTighten(string[] args)
325→    {
326→        if (args.Length < 3) return "ERR:tighten <force_N> <len_mm> <torque_Nm>";
327→        int force = int.Parse(args[0]);
328→        double length = double.Parse(args[1]);
329→        double torque = double.Parse(args[2]);
330→
331→        await CbClient.TightenAsync(force, length, torque);
332→        var done = await WaitUntilDone(waitStart: true);
333→        var achieved = await CbClient.GetTorqueAsync();
334→        var error = await CbClient.GetErrorCodeAsync();
335→
336→        bool success;
337→        string response;
338→        if (!done)
339→        {
340→            success = false;
341→            response = $"ERR:tighten timeout,torque={achieved:F2},error={error}";
342→        }
343→        else if (error != 0)
344→        {
345→            success = false;
346→            response = $"ERR:tighten error={error},torque={achieved:F2}";
347→        }
348→        else if (achieved < 0.15)
349→        {
350→            // 토크 부족 → NG (재시도 필요)
351→            success = false;
352→            await WaitRetract();
353→            response = $"OK:tighten torque={achieved:F2}";
354→        }
355→        else
356→        {
357→            success = true;
358→            await WaitRetract();
359→            response = $"OK:tighten torque={achieved:F2}";
360→        }
361→
362→        _lastTightenOk = success;
363→
364→        // 시나리오 실행 중이면 결과 기록 + 성공 시만 스텝 진행
365→        if (_scenarioRunning && _scenario != null && _currentStepIndex < _scenario.Operations.Count)
366→        {
367→            var op = _scenario.Operations[_currentStepIndex];
368→            var status = success ? HoleStatus.Ok : HoleStatus.Ng;
369→            PlateData?.SetResult(op.Col, op.Row, status, achieved);
370→
371→            Log("시나리오", $"스텝 {_currentStepIndex + 1} 결과: {(success ? "OK" : "NG")}, torque={achieved:F2}");
372→            StepCompleted?.Invoke(_currentStepIndex, op, success, achieved);
373→
374→            // NG면 스텝 진행 안 함 (next_step에서 같은 홀 반환 → 재시도)
375→            if (!success)
376→            {
377→                Log("시나리오", $"스텝 {_currentStepIndex + 1} 재시도 필요 (torque={achieved:F2} < 0.15)");
378→                return response;
379→            }
380→
381→            _currentStepIndex++;
382→
383→            if (_currentStepIndex >= _scenario.Operations.Count)
384→            {
385→                _scenarioRunning = false;
386→                Log("시나리오", $"전체 완료 ({_scenario.Operations.Count}개 스텝)");
387→                ScenarioCompleted?.Invoke();
388→            }
389→        }
390→
391→        return response;
392→    }
393→
394→    private async Task<string> CmdLoosen(string[] args)
395→    {
396→        if (args.Length < 2) return "ERR:loosen <force_N> <len_mm>";
397→        int force = int.Parse(args[0]);
398→        double length = double.Parse(args[1]);
399→
400→        await CbClient.LoosenAsync(force, length);
401→        var done = await WaitUntilDone(waitStart: true);
402→        var error = await CbClient.GetErrorCodeAsync();
403→        if (!done) return $"ERR:loosen timeout,error={error}";
404→        if (error != 0) return $"ERR:loosen error={error}";
405→        await WaitRetract();
406→        return "OK:loosen";
407→    }
408→
409→    private async Task<string> CmdShank(string[] args)
410→    {
411→        if (args.Length < 1) return "ERR:shank <pos> (0=후퇴, 55=전진)";
412→        int pos = int.Parse(args[0]);
413→        await CbClient.MoveShankAsync(pos);
414→        return "OK:shank";
415→    }
416→
417→    private async Task<string> CmdStop()
418→    {
419→        await CbClient.StopAsync();
420→        return "OK:stop";
421→    }
422→
423→    private async Task<string> CmdStatus()
424→    {
425→        var error = await CbClient.GetErrorCodeAsync();
426→        var safety = await CbClient.GetZSafetyActivatedAsync();
427→
428→        if (error != 0 || safety)
429→        {
430→            Log("복구", $"에러/안전 감지 (error={error}, safety={safety}), 자동 복구...");
431→            await CbClient.MoveShankAsync(0);
432→            await Task.Delay(3000);
433→            await WaitUntilDone(timeout: 10);
434→
435→            var error2 = await CbClient.GetErrorCodeAsync();
436→            var safety2 = await CbClient.GetZSafetyActivatedAsync();
437→            if (error2 == 0 && !safety2)
438→                Log("복구", "복구 완료");
439→            else
440→                Log("복구", $"복구 실패 (error={error2}, safety={safety2})");
441→        }
442→
443→        var busy = await CbClient.GetBusyAsync();
444→        var torque = await CbClient.GetTorqueAsync();
445→        error = await CbClient.GetErrorCodeAsync();
446→        return $"OK:busy={Convert.ToInt32(busy)},torque={torque:F2},error={error}";
447→    }
448→
449→    private async Task<string> CmdRecover()
450→    {
451→        Log("복구", "수동 복구 시작 (샹크 후퇴)...");
452→        await CbClient.MoveShankAsync(0);
453→        await Task.Delay(3000);
454→        await WaitUntilDone(timeout: 10);
455→        var error = await CbClient.GetErrorCodeAsync();
456→        var safety = await CbClient.GetZSafetyActivatedAsync();
457→        if (error == 0 && !safety)
458→        {
459→            Log("복구", "복구 완료");
460→            return "OK:recover";
461→        }
462→        Log("복구", $"복구 실패 (error={error}, safety={safety})");
463→        return $"ERR:recover error={error},safety={Convert.ToInt32(safety)}";
464→    }
465→
466→    private async Task<string> CmdRaw(string[] args)
467→    {
468→        if (args.Length == 0) return "ERR:raw <method> [args...]";
469→        var method = args[0];
470→        var callArgs = new object[args.Length - 1];
471→        for (int i = 1; i < args.Length; i++)
472→        {
473→            if (int.TryParse(args[i], out var iv)) callArgs[i - 1] = iv;
474→            else if (double.TryParse(args[i], out var dv)) callArgs[i - 1] = dv;
475→            else callArgs[i - 1] = args[i];
476→        }
477→        var result = await CbClient.CallRawAsync(method, callArgs);
478→        return $"OK:{result}";
479→    }
