483→    #region 확장 명령 (시나리오 연동)
484→
485→    private string CmdNextHole()
486→    {
487→        if (PlateData == null) return "ERR:작업판 없음";
488→        var next = PlateData.GetNextEmpty();
489→        if (next == null) return "ERR:빈 홀 없음";
490→        return $"OK:{next.Value.col},{next.Value.row}";
491→    }
492→
493→    private string CmdHoleResult(string[] args)
494→    {
495→        if (PlateData == null) return "ERR:작업판 없음";
496→        if (args.Length < 4) return "ERR:hole_result <col> <row> <ok|ng> <torque>";
497→        int col = int.Parse(args[0]);
498→        int row = int.Parse(args[1]);
499→        var status = args[2].ToLower() == "ok" ? HoleStatus.Ok : HoleStatus.Ng;
500→        double torque = double.Parse(args[3]);
501→        PlateData.SetResult(col, row, status, torque);
502→        return "OK:hole_result";
503→    }
504→
505→    private string CmdGetCoord(string[] args)
506→    {
507→        if (PlateData == null) return "ERR:작업판 없음";
508→        if (args.Length < 2) return "ERR:get_coord <col> <row>";
509→        int col = int.Parse(args[0]);
510→        int row = int.Parse(args[1]);
511→        // 20mm 피치 기준 좌표 (원점은 (0,0) 홀)
512→        double x = col * 20.0;
513→        double y = row * 20.0;
514→        return $"OK:{x:F1},{y:F1}";
515→    }
