517→    /// <summary>
518→    /// 마지막 체결 결과 반환 (OK 또는 NG)
519→    /// </summary>
520→    private string CmdTqDecision()
521→    {
522→        return _lastTightenOk ? "OK" : "NG";
523→    }
524→
525→    #endregion
526→
527→    #region 시나리오 연동 명령
528→
529→    /// <summary>
530→    /// TMflow → next_step: 다음 작업 스텝의 col,row 반환
531→    /// 시나리오 미실행 시 시작될 때까지 블로킹 대기 (최대 60초)
532→    /// 응답: OK:col,row  또는  DONE  또는  ERR:...
533→    /// </summary>
534→    private async Task<string> CmdNextStepAsync()
535→    {
536→        // 시나리오 완료 상태 → 즉시 DONE 반환
537→        if (!_scenarioRunning && _scenario != null && _currentStepIndex >= _scenario.Operations.Count)
538→        {
539→            return "DONE";
540→        }
541→
542→        // 시나리오 미실행 → 시작될 때까지 대기
543→        if (!_scenarioRunning || _scenario == null)
544→        {
545→            Log("시나리오", "next_step 대기 중 (PC에서 실행 버튼 대기)...");
546→
547→            TaskCompletionSource<bool> tcs;
548→            lock (_tcsLock)
549→            {
550→                _scenarioReadyTcs ??= new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);
551→                tcs = _scenarioReadyTcs;
552→            }
553→
554→            // 시나리오 시작 또는 서버 종료까지 무한 대기
555→            await tcs.Task;
556→
557→            if (!tcs.Task.Result)
558→            {
559→                return "ERR:시나리오 취소";
560→            }
561→
562→            Log("시나리오", "시나리오 시작 신호 수신");
563→        }
564→
565→        if (_scenario == null) return "ERR:시나리오 없음";
566→
567→        if (_currentStepIndex >= _scenario.Operations.Count)
568→        {
569→            _scenarioRunning = false;
570→            Log("시나리오", "전체 완료 (DONE)");
571→            ScenarioCompleted?.Invoke();
572→            return "DONE";
573→        }
574→
575→        var op = _scenario.Operations[_currentStepIndex];
576→        Log("시나리오", $"스텝 {_currentStepIndex + 1}/{_scenario.Operations.Count} → col={op.Col}, row={op.Row}");
577→        StepStarted?.Invoke(_currentStepIndex, op);
578→
579→        return $"OK:{op.Col},{op.Row}";
580→    }
581→
582→    #endregion
583→
584→    #region Busy 폴링
585→
586→    /// <summary>
587→    /// 동작 완료 대기 (busy 폴링)
588→    /// </summary>
589→    private async Task<bool> WaitUntilDone(double timeout = BUSY_TIMEOUT_SEC, bool waitStart = false)
590→    {
591→        if (waitStart)
592→        {
593→            // busy=true 시작 대기 (최대 3초)
594→            var sw = System.Diagnostics.Stopwatch.StartNew();
595→            while (sw.Elapsed.TotalSeconds < 3)
596→            {
597→                try
598→                {
599→                    if (await CbClient.GetBusyAsync()) break;
600→                }
601→                catch { }
602→                await Task.Delay(50);
603→            }
604→        }
605→
606→        // busy=false 대기
607→        var sw2 = System.Diagnostics.Stopwatch.StartNew();
608→        while (sw2.Elapsed.TotalSeconds < timeout)
609→        {
610→            try
611→            {
612→                if (!await CbClient.GetBusyAsync()) return true;
613→            }
614→            catch { }
615→            await Task.Delay((int)(BUSY_POLL_SEC * 1000));
616→        }
617→        return false;
618→    }
619→
620→    /// <summary>
621→    /// 샹크 자동 후퇴 완료 대기
622→    /// </summary>
623→    private async Task WaitRetract()
624→    {
625→        await Task.Delay(500);
626→        var sw = System.Diagnostics.Stopwatch.StartNew();
627→        while (sw.Elapsed.TotalSeconds < 10)
628→        {
629→            try
630→            {
631→                if (!await CbClient.GetBusyAsync()) return;
632→            }
633→            catch { }
634→            await Task.Delay((int)(BUSY_POLL_SEC * 1000));
635→        }
636→    }
637→
638→    #endregion
639→}
