  1→using System.Globalization;
  2→using System.Net.Http;
  3→using System.Text;
  4→using System.Xml.Linq;
  5→
  6→namespace TmRobotEx.Bridge;
  7→
  8→/// <summary>
  9→/// Compute Box XML-RPC 클라이언트.
 10→/// HttpClient로 XML-RPC 요청/응답을 직접 구현 (외부 라이브러리 없음).
 11→/// </summary>
 12→public class ComputeBoxClient : IDisposable
 13→{
 14→    private readonly HttpClient _http;
 15→    private const int DEV_INDEX = 0;
 16→
 17→    public string Url { get; }
 18→    public event Action<string>? LogMessage;
 19→
 20→    public ComputeBoxClient(string url, int timeoutSec)
 21→    {
 22→        Url = url;
 23→        _http = new HttpClient { Timeout = TimeSpan.FromSeconds(timeoutSec) };
 24→    }
 25→
 26→    #region 공개 메서드
 27→
 28→    public async Task ConfigAsync(double extender = 0)
 29→    {
 30→        await CallAsync("sd_config", DEV_INDEX, extender);
 31→    }
 32→
 33→    public async Task PickupScrewAsync(int force, double length)
 34→    {
 35→        await CallAsync("sd_pickup_screw", DEV_INDEX, force, length);
 36→    }
 37→
 38→    public async Task TightenAsync(int force, double length, double torque)
 39→    {
 40→        await CallAsync("sd_tighten", DEV_INDEX, force, length, torque);
 41→    }
 42→
 43→    public async Task LoosenAsync(int force, double length)
 44→    {
 45→        await CallAsync("sd_loosen", DEV_INDEX, force, length);
 46→    }
 47→
 48→    public async Task MoveShankAsync(int position)
 49→    {
 50→        await CallAsync("sd_move_shank", DEV_INDEX, position);
 51→    }
 52→
 53→    public async Task StopAsync()
 54→    {
 55→        await CallAsync("sd_stop", DEV_INDEX);
 56→    }
 57→
 58→    public async Task<bool> GetBusyAsync()
 59→    {
 60→        var result = await CallSilentAsync("sd_get_screwdriver_busy", DEV_INDEX);
 61→        return ParseBool(result);
 62→    }
 63→
 64→    public async Task<double> GetTorqueAsync()
 65→    {
 66→        var result = await CallAsync("sd_get_achieved_torque", DEV_INDEX);
 67→        return ParseDouble(result);
 68→    }
 69→
 70→    public async Task<int> GetErrorCodeAsync()
 71→    {
 72→        var result = await CallAsync("sd_get_error_code", DEV_INDEX);
 73→        return ParseInt(result);
 74→    }
 75→
 76→    public async Task<bool> GetZSafetyActivatedAsync()
 77→    {
 78→        var result = await CallAsync("sd_get_z_safety_activated", DEV_INDEX);
 79→        return ParseBool(result);
 80→    }
 81→
 82→    /// <summary>
 83→    /// 임의 메서드 직접 호출
 84→    /// </summary>
 85→    public async Task<string> CallRawAsync(string method, params object[] args)
 86→    {
 87→        var result = await CallAsync(method, args);
 88→        return result?.Value ?? "";
 89→    }
 90→
 91→    #endregion
 92→
 93→    #region XML-RPC 통신
 94→
 95→    /// <summary>
 96→    /// XML-RPC 호출 (HttpClient POST)
 97→    /// </summary>
 98→    private async Task<XElement?> CallAsync(string method, params object[] args)
 99→    {
100→        var xml = BuildRequest(method, args);
101→        var content = new StringContent(xml, Encoding.UTF8, "text/xml");
102→
103→        HttpResponseMessage response;
104→        try
105→        {
106→            response = await _http.PostAsync(Url, content);
107→            response.EnsureSuccessStatusCode();
108→        }
109→        catch (Exception ex)
110→        {
111→            LogMessage?.Invoke($"[CB] {method} 실패: {ex.Message}");
112→            throw;
113→        }
114→
115→        var responseXml = await response.Content.ReadAsStringAsync();
116→        return ParseResponse(responseXml);
117→    }
118→
119→    /// <summary>
120→    /// XML-RPC 호출 (silent — 실패 시에만 로그)
121→    /// </summary>
122→    private async Task<XElement?> CallSilentAsync(string method, params object[] args)
123→    {
124→        var xml = BuildRequest(method, args);
125→        var content = new StringContent(xml, Encoding.UTF8, "text/xml");
126→
127→        var response = await _http.PostAsync(Url, content);
128→        response.EnsureSuccessStatusCode();
129→
130→        var responseXml = await response.Content.ReadAsStringAsync();
131→        return ParseResponse(responseXml);
132→    }
133→
134→    /// <summary>
135→    /// XML-RPC 요청 XML 생성
136→    /// </summary>
137→    private static string BuildRequest(string method, object[] args)
138→    {
139→        var sb = new StringBuilder();
140→        sb.Append("<?xml version=\"1.0\"?>");
141→        sb.Append("<methodCall>");
142→        sb.Append($"<methodName>{method}</methodName>");
143→        sb.Append("<params>");
144→        foreach (var arg in args)
145→        {
146→            sb.Append("<param><value>");
147→            sb.Append(FormatValue(arg));
148→            sb.Append("</value></param>");
149→        }
150→        sb.Append("</params>");
151→        sb.Append("</methodCall>");
152→        return sb.ToString();
153→    }
154→
155→    /// <summary>
156→    /// 값 타입에 따른 XML-RPC 포맷
157→    /// </summary>
158→    private static string FormatValue(object value)
159→    {
160→        return value switch
161→        {
162→            int i => $"<int>{i}</int>",
163→            long l => $"<int>{l}</int>",
164→            double d => $"<double>{d.ToString(CultureInfo.InvariantCulture)}</double>",
165→            float f => $"<double>{f.ToString(CultureInfo.InvariantCulture)}</double>",
166→            bool b => $"<boolean>{(b ? 1 : 0)}</boolean>",
167→            string s => $"<string>{System.Security.SecurityElement.Escape(s)}</string>",
168→            _ => $"<string>{System.Security.SecurityElement.Escape(value.ToString() ?? "")}</string>"
169→        };
170→    }
171→
172→    /// <summary>
173→    /// XML-RPC 응답 파싱 (fault 체크 포함)
174→    /// </summary>
175→    private static XElement? ParseResponse(string xml)
176→    {
177→        var doc = XDocument.Parse(xml);
178→        var fault = doc.Descendants("fault").FirstOrDefault();
179→        if (fault != null)
180→        {
181→            var faultString = fault.Descendants("string").FirstOrDefault()?.Value ?? "Unknown fault";
182→            throw new Exception($"XML-RPC Fault: {faultString}");
183→        }
184→
185→        // params/param/value 반환
186→        return doc.Descendants("value").FirstOrDefault();
187→    }
188→
189→    private static bool ParseBool(XElement? value)
190→    {
191→        if (value == null) return false;
192→        var boolElem = value.Element("boolean");
193→        if (boolElem != null) return boolElem.Value == "1";
194→        // int로 반환되는 경우도 있음
195→        var intElem = value.Element("int") ?? value.Element("i4");
196→        if (intElem != null) return intElem.Value != "0";
197→        return bool.TryParse(value.Value, out var b) && b;
198→    }
199→
200→    private static double ParseDouble(XElement? value)
201→    {
202→        if (value == null) return 0;
203→        var elem = value.Element("double") ?? value.Element("int") ?? value.Element("i4");
204→        if (elem != null && double.TryParse(elem.Value, CultureInfo.InvariantCulture, out var d))
205→            return d;
206→        if (double.TryParse(value.Value, CultureInfo.InvariantCulture, out var d2))
207→            return d2;
208→        return 0;
209→    }
210→
211→    private static int ParseInt(XElement? value)
212→    {
213→        if (value == null) return 0;
214→        var elem = value.Element("int") ?? value.Element("i4");
215→        if (elem != null && int.TryParse(elem.Value, out var i))
216→            return i;
217→        if (int.TryParse(value.Value, out var i2))
218→            return i2;
219→        return 0;
220→    }
221→
222→    #endregion
223→
224→    public void Dispose()
225→    {
226→        _http.Dispose();
227→        GC.SuppressFinalize(this);
228→    }
229→}
