664→    /// <summary>
665→    /// 단위 구체 메시 생성 (반지름 1, 원점 중심)
666→    /// </summary>
667→    private static MeshGeometry3D CreateUnitSphereMesh(int thetaDiv = 8, int phiDiv = 5)
668→    {
669→        var mesh = new MeshGeometry3D();
670→        for (int pi = 0; pi <= phiDiv; pi++)
671→        {
672→            double phi = Math.PI * pi / phiDiv;
673→            for (int ti = 0; ti <= thetaDiv; ti++)
674→            {
675→                double theta = 2 * Math.PI * ti / thetaDiv;
676→                double x = Math.Sin(phi) * Math.Cos(theta);
677→                double y = Math.Sin(phi) * Math.Sin(theta);
678→                double z = Math.Cos(phi);
679→                mesh.Positions.Add(new Point3D(x, y, z));
680→                mesh.Normals.Add(new Vector3D(x, y, z));
681→            }
682→        }
683→        for (int pi = 0; pi < phiDiv; pi++)
684→        {
685→            for (int ti = 0; ti < thetaDiv; ti++)
686→            {
687→                int i0 = pi * (thetaDiv + 1) + ti;
688→                int i1 = i0 + 1;
689→                int i2 = i0 + thetaDiv + 1;
690→                int i3 = i2 + 1;
691→                mesh.TriangleIndices.Add(i0);
692→                mesh.TriangleIndices.Add(i2);
693→                mesh.TriangleIndices.Add(i1);
694→                mesh.TriangleIndices.Add(i1);
695→                mesh.TriangleIndices.Add(i2);
696→                mesh.TriangleIndices.Add(i3);
697→            }
698→        }
699→        mesh.Freeze();
700→        return mesh;
701→    }
702→
703→    private void Build3DWorkPlate()
704→    {
705→        // 3D 모델 좌표 직접 사용 (FK 오프셋 불필요)
706→        var p1 = CalP1;
707→        var p2 = CalP2;
708→        var p3 = CalP3;
709→
710→        // 그리드 벡터
711→        var rowStep = (p2 - p1) / (WorkPlateData.ROWS - 1);  // 15행, 14 간격
712→        var colStep = (p3 - p2) / (WorkPlateData.COLS - 1);  // 9열, 8 간격
713→
714→        // 공유 구체 메시 (반지름 5mm 스케일 적용)
715→        var sphereMesh = CreateUnitSphereMesh();
716→        var group = new Model3DGroup();
717→        var yellowBrush = new SolidColorBrush(Color.FromRgb(255, 204, 0));
718→
719→        // 135개 홀
720→        for (int r = 0; r < WorkPlateData.ROWS; r++)
721→        {
722→            for (int c = 0; c < WorkPlateData.COLS; c++)
723→            {
724→                var pos = p1 + r * rowStep + c * colStep;
725→                var tg = new Transform3DGroup();
726→                tg.Children.Add(new ScaleTransform3D(5, 5, 5));
727→                tg.Children.Add(new TranslateTransform3D(pos.X, pos.Y, pos.Z));
728→
729→                var model = new GeometryModel3D
730→                {
731→                    Geometry = sphereMesh,
732→                    Material = Mat3DEmpty,
733→                    BackMaterial = Mat3DEmpty,
734→                    Transform = tg
735→                };
736→                _hole3D[r * WorkPlateData.COLS + c] = model;
737→                group.Children.Add(model);
738→            }
739→        }
740→
741→        _plate3DVisual = new ModelVisual3D { Content = group };
742→        Viewport3D.Children.Add(_plate3DVisual);
743→
744→        // 테두리선 (노란색)
745→        var p00 = p1;
746→        var pR0 = p1 + (WorkPlateData.ROWS - 1) * rowStep;
747→        var p0C = p1 + (WorkPlateData.COLS - 1) * colStep;
748→        var pRC = p1 + (WorkPlateData.ROWS - 1) * rowStep + (WorkPlateData.COLS - 1) * colStep;
749→
750→        _plateBorder = new LinesVisual3D
751→        {
752→            Color = Colors.Yellow,
753→            Thickness = 2,
754→            Points = new Point3DCollection(new[] { p00, pR0, pR0, pRC, pRC, p0C, p0C, p00 })
755→        };
756→        Viewport3D.Children.Add(_plateBorder);
757→
758→        // 코너 라벨
759→        Viewport3D.Children.Add(new BillboardTextVisual3D
760→        {
761→            Text = "(0,0)", Foreground = yellowBrush, FontSize = 11,
762→            Position = new Point3D(p00.X, p00.Y, p00.Z + 15)
763→        });
764→        Viewport3D.Children.Add(new BillboardTextVisual3D
765→        {
766→            Text = $"(0,{WorkPlateData.COLS - 1})", Foreground = yellowBrush, FontSize = 11,
767→            Position = new Point3D(p0C.X, p0C.Y, p0C.Z + 15)
768→        });
769→        Viewport3D.Children.Add(new BillboardTextVisual3D
770→        {
771→            Text = $"({WorkPlateData.ROWS - 1},0)", Foreground = yellowBrush, FontSize = 11,
772→            Position = new Point3D(pR0.X, pR0.Y, pR0.Z + 15)
773→        });
774→        Viewport3D.Children.Add(new BillboardTextVisual3D
775→        {
776→            Text = $"({WorkPlateData.ROWS - 1},{WorkPlateData.COLS - 1})", Foreground = yellowBrush, FontSize = 11,
777→            Position = new Point3D(pRC.X, pRC.Y, pRC.Z + 15)
778→        });
779→
780→    }
