782→    /// <summary>
783→    /// 3D 작업판 홀 색상 갱신 (WorkPlateData 상태 반영)
784→    /// </summary>
785→    private void Update3DPlate()
786→    {
787→        if (_plate3DVisual == null) return;
788→
789→        for (int r = 0; r < WorkPlateData.ROWS; r++)
790→        {
791→            for (int c = 0; c < WorkPlateData.COLS; c++)
792→            {
793→                var hole = _plateData.GetHole(c, r);
794→                var mat = hole.Status switch
795→                {
796→                    HoleStatus.Ok => Mat3DOk,
797→                    HoleStatus.Ng => Mat3DNg,
798→                    _ => Mat3DEmpty
799→                };
800→                var model = _hole3D[r * WorkPlateData.COLS + c];
801→                if (model.Material != mat)
802→                {
803→                    model.Material = mat;
804→                    model.BackMaterial = mat;
805→                }
806→            }
807→        }
808→    }
