  1→using System.IO;
  2→using System.Net.Sockets;
  3→using System.Text;
  4→using System.Text.Json;
  5→
  6→namespace TmRobotEx.Robot;
  7→
  8→/// <summary>
  9→/// TM Robot Ethernet Slave (TMSVR) TCP 통신 클라이언트.
 10→/// 포트 5891로 접속하여 관절 각도 및 TCP 좌표를 수신.
 11→/// </summary>
 12→public class TmRobotClient : IDisposable
 13→{
 14→    private TcpClient? _tcp;
 15→    private NetworkStream? _stream;
 16→    private CancellationTokenSource? _cts;
 17→    private Task? _receiveTask;
 18→    private readonly StringBuilder _recvBuffer = new();
 19→
 20→    // TMSCT 비상정지용
 21→    private int _sctCmdId;
 22→
 23→    private bool _isConnected;
 24→
 25→    public string Host { get; set; } = "192.168.1.50";
 26→    public int Port { get; set; } = 5891;
 27→    public bool IsConnected => _isConnected;
 28→
 29→    /// <summary>
 30→    /// 관절 각도(J1~J6, 도) + TCP 좌표(X,Y,Z,Rx,Ry,Rz) 수신 이벤트
 31→    /// </summary>
 32→    public event Action<double[], double[]>? DataReceived;
 33→
 34→    /// <summary>
 35→    /// 연결 상태 변경 이벤트
 36→    /// </summary>
 37→    public event Action<bool, string>? ConnectionChanged;
 38→
 39→    /// <summary>
 40→    /// 로그 이벤트
 41→    /// </summary>
 42→    public event Action<string>? LogMessage;
 43→
 44→    public async Task ConnectAsync()
 45→    {
 46→        try
 47→        {
 48→            Disconnect();
 49→
 50→            _tcp = new TcpClient();
 51→            _tcp.ReceiveTimeout = 5000;
 52→            _tcp.SendTimeout = 5000;
 53→
 54→            LogMessage?.Invoke($"로봇 연결 시도: {Host}:{Port}");
 55→            await _tcp.ConnectAsync(Host, Port);
 56→
 57→            _stream = _tcp.GetStream();
 58→            _recvBuffer.Clear();
 59→            _isConnected = true;
 60→
 61→            LogMessage?.Invoke($"로봇 연결 성공: {Host}:{Port}");
 62→            ConnectionChanged?.Invoke(true, $"{Host}:{Port}");
 63→
 64→            _cts = new CancellationTokenSource();
 65→            _receiveTask = Task.Run(() => ReceiveLoop(_cts.Token));
 66→        }
 67→        catch (Exception ex)
 68→        {
 69→            LogMessage?.Invoke($"로봇 연결 실패: {ex.Message}");
 70→            CleanupResources();
 71→            ConnectionChanged?.Invoke(false, ex.Message);
 72→        }
 73→    }
 74→
 75→    public void Disconnect()
 76→    {
 77→        var wasConnected = _isConnected;
 78→        CleanupResources();
 79→        if (wasConnected)
 80→            ConnectionChanged?.Invoke(false, "연결 해제");
 81→    }
 82→
 83→    private void CleanupResources()
 84→    {
 85→        _isConnected = false;
 86→        try
 87→        {
 88→            _cts?.Cancel();
 89→            _stream?.Close();
 90→            _tcp?.Close();
 91→        }
 92→        catch { }
 93→        finally
 94→        {
 95→            _stream = null;
 96→            _tcp = null;
 97→            _cts = null;
 98→            _receiveTask = null;
 99→            _recvBuffer.Clear();
100→        }
101→    }
102→
103→    private async Task ReceiveLoop(CancellationToken token)
104→    {
105→        var buffer = new byte[4096];
106→
107→        try
108→        {
109→            while (!token.IsCancellationRequested && _stream != null)
110→            {
111→                int bytesRead = await _stream.ReadAsync(buffer, 0, buffer.Length, token);
112→                if (bytesRead == 0)
113→                {
114→                    LogMessage?.Invoke("로봇 서버가 연결을 종료했습니다.");
115→                    break;
116→                }
117→
118→                var received = Encoding.ASCII.GetString(buffer, 0, bytesRead);
119→                _recvBuffer.Append(received);
120→                ProcessBuffer();
121→            }
122→        }
123→        catch (OperationCanceledException) { }
124→        catch (Exception ex)
125→        {
126→            if (!token.IsCancellationRequested)
127→                LogMessage?.Invoke($"로봇 수신 오류: {ex.Message}");
128→        }
129→
130→        if (_isConnected)
131→        {
132→            _isConnected = false;
133→            ConnectionChanged?.Invoke(false, "연결 종료");
134→        }
135→    }
136→
137→    private void ProcessBuffer()
138→    {
139→        var buf = _recvBuffer.ToString();
140→
141→        while (true)
142→        {
143→            int headerIdx = buf.IndexOf("$TMSVR", StringComparison.Ordinal);
144→            if (headerIdx < 0)
145→            {
146→                _recvBuffer.Clear();
147→                return;
148→            }
149→
150→            if (headerIdx > 0)
151→                buf = buf[headerIdx..];
152→
153→            int endIdx = FindPacketEnd(buf);
154→            if (endIdx < 0)
155→                break;
156→
157→            var packet = buf[..endIdx];
158→            buf = buf[endIdx..];
159→            ParseTmsvrPacket(packet);
160→        }
161→
162→        _recvBuffer.Clear();
163→        _recvBuffer.Append(buf);
164→    }
165→
166→    private static int FindPacketEnd(string buf)
167→    {
168→        int searchFrom = 6;
169→        while (searchFrom < buf.Length)
170→        {
171→            int starIdx = buf.IndexOf(",*", searchFrom, StringComparison.Ordinal);
172→            if (starIdx < 0) return -1;
173→
174→            if (starIdx + 4 <= buf.Length)
175→            {
176→                char h1 = buf[starIdx + 2];
177→                char h2 = buf[starIdx + 3];
178→                if (IsHexChar(h1) && IsHexChar(h2))
179→                {
180→                    int endIdx = starIdx + 4;
181→                    if (endIdx < buf.Length && buf[endIdx] == '\r') endIdx++;
182→                    if (endIdx < buf.Length && buf[endIdx] == '\n') endIdx++;
183→                    return endIdx;
184→                }
185→            }
186→            searchFrom = starIdx + 1;
187→        }
188→        return -1;
189→    }
190→
191→    private static bool IsHexChar(char c) =>
192→        (c >= '0' && c <= '9') || (c >= 'A' && c <= 'F') || (c >= 'a' && c <= 'f');
193→
194→    private void ParseTmsvrPacket(string packet)
195→    {
196→        try
197→        {
198→            int commaCount = 0;
199→            int jsonStart = -1;
200→            for (int i = 0; i < packet.Length; i++)
201→            {
202→                if (packet[i] == ',')
203→                {
204→                    commaCount++;
205→                    if (commaCount == 4)
206→                    {
207→                        jsonStart = i + 1;
208→                        break;
209→                    }
210→                }
211→            }
212→
213→            if (jsonStart < 0) return;
214→
215→            int checksumIdx = packet.LastIndexOf(",*", StringComparison.Ordinal);
216→            if (checksumIdx < jsonStart) return;
217→
218→            var jsonStr = packet[jsonStart..checksumIdx];
219→            var items = JsonSerializer.Deserialize<JsonElement[]>(jsonStr);
220→            if (items == null) return;
221→
222→            double[]? jointAngles = null;
223→            double[]? tcpCoord = null;
224→
225→            foreach (var item in items)
226→            {
227→                var itemName = item.GetProperty("Item").GetString();
228→                var value = item.GetProperty("Value");
229→
230→                if (itemName == "Joint_Angle" && value.ValueKind == JsonValueKind.Array)
231→                {
232→                    jointAngles = new double[6];
233→                    for (int i = 0; i < Math.Min(value.GetArrayLength(), 6); i++)
234→                        jointAngles[i] = value[i].GetDouble();
235→                }
236→                else if ((itemName == "Coord_Base_Tool" || itemName == "Coord_Robot_Tool")
237→                         && value.ValueKind == JsonValueKind.Array)
238→                {
239→                    tcpCoord = new double[6];
240→                    for (int i = 0; i < Math.Min(value.GetArrayLength(), 6); i++)
241→                        tcpCoord[i] = value[i].GetDouble();
242→                }
243→            }
244→
245→            if (jointAngles != null)
246→                DataReceived?.Invoke(jointAngles, tcpCoord ?? new double[6]);
247→        }
248→        catch (Exception ex)
249→        {
250→            LogMessage?.Invoke($"패킷 파싱 오류: {ex.Message}");
251→        }
252→    }
253→
254→    #region TMSCT 비상정지
255→
256→    public async Task<string> SendPauseAsync()
257→    {
258→        return await SendTmsctScriptAsync("Pause()");
259→    }
260→
261→    public async Task<string> SendResumeAsync()
262→    {
263→        return await SendTmsctScriptAsync("Resume()");
264→    }
265→
266→    public async Task<string> SendStopAsync()
267→    {
268→        return await SendTmsctScriptAsync("StopAndClearBuffer()");
269→    }
270→
271→    private async Task<string> SendTmsctScriptAsync(string script)
272→    {
273→        TcpClient? sctTcp = null;
274→        try
275→        {
276→            sctTcp = new TcpClient { SendTimeout = 3000, ReceiveTimeout = 3000 };
277→            await sctTcp.ConnectAsync(Host, 5890);
278→
279→            var stream = sctTcp.GetStream();
280→            var id = (++_sctCmdId).ToString("D2");
281→            var packet = BuildTmsctPacket(id, script);
282→
283→            LogMessage?.Invoke($"[TMSCT] 전송: {packet.TrimEnd()}");
284→
285→            var bytes = Encoding.ASCII.GetBytes(packet);
286→            await stream.WriteAsync(bytes);
287→
288→            var buf = new byte[1024];
289→            var readTask = stream.ReadAsync(buf, 0, buf.Length);
290→            if (await Task.WhenAny(readTask, Task.Delay(3000)) == readTask)
291→            {
292→                int n = readTask.Result;
293→                var response = Encoding.ASCII.GetString(buf, 0, n);
294→                LogMessage?.Invoke($"[TMSCT] 응답: {response.TrimEnd()}");
295→                return response;
296→            }
297→            else
298→            {
299→                LogMessage?.Invoke("[TMSCT] 응답 타임아웃");
300→                return "TIMEOUT";
301→            }
302→        }
303→        catch (Exception ex)
304→        {
305→            LogMessage?.Invoke($"[TMSCT] 오류: {ex.Message}");
306→            return $"ERROR: {ex.Message}";
307→        }
308→        finally
309→        {
310→            try { sctTcp?.Close(); } catch { }
311→        }
312→    }
313→
314→    private static string BuildTmsctPacket(string id, string script)
315→    {
316→        var data = $"{id},{script}";
317→        var length = Encoding.ASCII.GetByteCount(data);
318→        var body = $"TMSCT,{length},{data},";
319→        var checksum = CalcChecksum(body);
320→        return $"${body}*{checksum}\r\n";
321→    }
322→
323→    private static string CalcChecksum(string content)
324→    {
325→        int xor = 0;
326→        foreach (char c in content)
327→            xor ^= c;
328→        return xor.ToString("X2");
329→    }
330→
331→    #endregion
332→
333→    public void Dispose()
334→    {
335→        Disconnect();
336→        GC.SuppressFinalize(this);
337→    }
338→}
