63→            var entry = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] [{source}]\n" +
64→                        $"Message: {ex.Message}\n" +
65→                        $"StackTrace: {ex.StackTrace}\n" +
66→                        $"---\n";
